<?php
namespace App\Domain\Shops;use App\Domain\WorldCatalog\ItemType;use App\Models\Item;use InvalidArgumentException;
final class NpcSaleItemValidator{private static $allowed=[ItemType::MATERIAL,ItemType::CONSUMABLE,ItemType::EQUIPMENT,ItemType::DRAGON_MATERIAL];public function evaluate(Item $item){if(!$item->is_sellable)return new ShopSaleItemEvaluation(false,'item_not_sellable');if(!in_array($item->item_type,self::$allowed,true))return new ShopSaleItemEvaluation(false,'protected_item_type');$price=$item->sell_price;if(!is_int($price)||$price<1)return new ShopSaleItemEvaluation(false,'invalid_price_configuration');return new ShopSaleItemEvaluation(true);}public function validate(Item $item){$evaluation=$this->evaluate($item);if(!$evaluation->eligible())throw new InvalidArgumentException($evaluation->reasonCode());}}
